SET SESSION FOREIGN_KEY_CHECKS = 0;
SET SESSION UNIQUE_CHECKS = 0;
SET SESSION AUTOCOMMIT = 0;

CREATE DATABASE IF NOT EXISTS exoplanet_db;
USE exoplanet_db;

DROP TABLE IF EXISTS exoplanets;
CREATE TABLE exoplanets (
                            id INT AUTO_INCREMENT PRIMARY KEY,
                            planet_name VARCHAR(100) NOT NULL,
                            host_star_name VARCHAR(100) NOT NULL,
                            discovery_year INT COMMENT 'Jahr der Entdeckung',
                            distance_lightyears DOUBLE COMMENT 'Entfernung zur Erde in Lichtjahren',
                            planet_mass_earth DOUBLE COMMENT 'Masse relativ zur Erde (Erde = 1.0)',
                            planet_radius_earth DOUBLE COMMENT 'Radius relativ zur Erde (Erde = 1.0)',
                            orbital_period_days DOUBLE COMMENT 'Dauer eines Jahres auf dem Planeten in Erdtagen',
                            equilibrium_temp_k DOUBLE COMMENT 'Gleichgewichtstemperatur in Kelvin (ohne Treibhauseffekt)',
                            insolation_flux DOUBLE COMMENT 'Eintreffende Sternenstrahlung (Erde = 1.0)',
                            star_spectral_type VARCHAR(50) COMMENT 'Spektralklasse des Sterns (z.B. G2V für unsere Sonne, M für Rote Zwerge)',
                            esi_score DECIMAL(5, 4) COMMENT 'Earth Similarity Index (Schätzwert zwischen 0 und 1)',
                            notes TEXT COMMENT 'Besonderheiten zur Atmosphäre oder Habitabilität'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


