-- ==========================================
-- DATEN-LÜCKEN FÜLLER TEIL: TEMPERATUR, MASSE
-- ==========================================
UPDATE exoplanets
SET equilibrium_temp_k = 255 * POW(insolation_flux, 0.25),
    notes = 'Temperatur aus Strahlungsfluss abgeleitet'
WHERE equilibrium_temp_k IS NULL
  AND insolation_flux IS NOT NULL;

-- ==========================================
-- PROFESSIONELLER MASSE-PATCH (Masse-Radius-Beziehung)
-- ==========================================
UPDATE exoplanets
SET
    planet_mass_earth =
        CASE
            -- 1. Felsplaneten (Radius bis 1.5 Erdradien)
            -- Hohe Dichte (Gestein/Eisen), Masse wächst stark mit dem Volumen.
            WHEN planet_radius_earth <= 1.5 THEN POW(planet_radius_earth, 3)

            -- 2. Mini-Neptune / Eisriesen (Radius 1.5 bis 4.0 Erdradien)
            -- Sie haben dicke Gashüllen. Die Dichte sinkt, die Masse wächst langsamer.
            WHEN planet_radius_earth > 1.5 AND planet_radius_earth <= 4.0 THEN POW(planet_radius_earth, 2)

            -- 3. Gasriesen (Radius über 4.0 Erdradien, ab Uranus/Neptun-Größe)
            -- Fast nur leichtes Gas. Die Masse wächst im Vergleich zum riesigen Radius nur noch langsam.
            WHEN planet_radius_earth > 4.0 THEN POW(planet_radius_earth, 1.5)
            END,
    notes = CONCAT(IFNULL(notes, ''), ' | Masse durch physikalisches Modell geschätzt')
WHERE
    planet_mass_earth IS NULL
  AND planet_radius_earth IS NOT NULL;

-- Berechne den ESI für alle Planeten, die genug Daten haben
UPDATE exoplanets
SET esi_score =
        POW(1 - ABS(planet_radius_earth - 1) / (planet_radius_earth + 1), 0.57) * POW(1 - ABS((planet_mass_earth / POW(planet_radius_earth, 3)) - 1) / ((planet_mass_earth / POW(planet_radius_earth, 3)) + 1), 1.07) *
        POW(1 - ABS(SQRT(planet_mass_earth / planet_radius_earth) - 1) / (SQRT(planet_mass_earth / planet_radius_earth) + 1), 0.70) *
        POW(1 - ABS(equilibrium_temp_k - 288) / (equilibrium_temp_k + 288), 5.58)
WHERE planet_radius_earth IS NOT NULL AND planet_mass_earth IS NOT NULL AND equilibrium_temp_k IS NOT NULL;

-- Optional: Setze Notizen für besonders hohe ESI-Werte
UPDATE exoplanets SET notes = 'Hohe Erdähnlichkeit' WHERE esi_score > 0.8;

COMMIT;
SET SESSION FOREIGN_KEY_CHECKS = 1;
SET SESSION UNIQUE_CHECKS = 1;